// ── Lookup Functions ──────────────────────────────────────────────

/** Map category slug → array of providers. */
const providersByCategory: Record<string, StoreData[]> = {};

for (const provider of allProviders) {
  // Match provider to its category by looking up the subCategory → slug mapping
  const catSlug = inferCategorySlug(provider.category);
  if (!providersByCategory[catSlug]) {
    providersByCategory[catSlug] = [];
  }
  providersByCategory[catSlug].push(provider);
}

function inferCategorySlug(category: string): string {
  const map: Record<string, string> = {
    "AC Repair": "ac-repair",
    "Painters": "painters",
    "Pest Control": "pest-control",
    "Plumbers": "plumbers",
    "Carpenters": "carpenters",
    "Electricians": "electricians",
    "Salons at Home": "salons-at-home",
    "Deep Cleaning": "deep-cleaning",
  };
  return map[category] || category.toLowerCase().replace(/\s+/g, "-");
}

/** Index providers by id for fast lookup. */
const providerById: Record<string, StoreData> = {};
for (const p of allProviders) {
  providerById[p.id] = p;
}

export function getServiceCategory(slug: string): ServiceCategoryInfo | undefined {
  return serviceCategories.find((c) => c.slug === slug);
}

export function getServiceProviders(categorySlug: string): StoreData[] {
  return providersByCategory[categorySlug] || [];
}

/** Returns every provider across all categories. Used by /services landing page. */
export function getAllServiceProviders(): StoreData[] {
  return allProviders;
}

/**
 * Returns providers grouped per category slug, in the SAME ORDER as
 * `serviceCategories`. Used by /services landing "All" view to render
 * one section per category with its own provider grid.
 */
export function getCategorizedProviders(): { category: ServiceCategoryInfo; providers: StoreData[] }[] {
  return serviceCategories.map((category) => ({
    category,
    providers: providersByCategory[category.slug] || [],
  }));
}

export function getServiceProviderById(id: string): StoreData | undefined {
  return providerById[id];
}